/** Suffix-based mode lookup for any clip name (falls back to "base" for unknown). */
export function getAnimationClipMode(clip: string): AnimationClipMode {
	if (clip.endsWith("_over")) return "override";
	if (clip.endsWith("_add")) return "additive";
	return "base";
}

